'use client';

import React, { useState, useEffect } from 'react';
import Header from '@/components/Header';
import Footer from '@/components/Footer';

interface Student {
  id: string;
  name: string;
  grade: number;
}

const PHONICS_SOUNDS = ['s', 'a', 't', 'i', 'p', 'n'];

export default function TeacherDashboard() {
  const [students, setStudents] = useState<Student[]>([]);
  const [formData, setFormData] = useState({
    student_id: '',
    session_date: new Date().toISOString().split('T')[0],
    sfl_existential: 3,
    sfl_relational: 3,
    sfl_material: 3,
    phonics_practiced: [] as string[],
    youtube_url: '',
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  useEffect(() => {
    fetch('/api/students')
      .then((res) => res.json())
      .then((data) => setStudents(data))
      .catch((err) => console.error('Error fetching students:', err));
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSliderChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: parseInt(value) }));
  };

  const handlePhonicsChange = (sound: string) => {
    setFormData((prev) => ({
      ...prev,
      phonics_practiced: prev.phonics_practiced.includes(sound)
        ? prev.phonics_practiced.filter((s) => s !== sound)
        : [...prev.phonics_practiced, sound],
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setMessage(null);

    try {
      const response = await fetch('/api/sessions', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      if (response.ok) {
        setMessage({ type: 'success', text: 'Laporan Berhasil Disimpan!' });
        setFormData({
          student_id: '',
          session_date: new Date().toISOString().split('T')[0],
          sfl_existential: 3,
          sfl_relational: 3,
          sfl_material: 3,
          phonics_practiced: [],
          youtube_url: '',
        });
        // Clear success message after 3 seconds
        setTimeout(() => setMessage(null), 3000);
      } else {
        const data = await response.json();
        setMessage({ type: 'error', text: data.error || 'Terjadi kesalahan.' });
      }
    } catch (err) {
      setMessage({ type: 'error', text: 'Gagal mengirim data. Periksa koneksi.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <Header />

      <main className="max-w-2xl mx-auto px-4 py-32">
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 md:p-10">
          <div className="mb-8">
            <h1 className="text-3xl font-bold text-[#2D5A27] mb-2">Teacher Dashboard</h1>
            <p className="text-gray-600">Catat perkembangan setiap murid di sesi hari ini.</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-8">
            {/* Student Select */}
            <div className="space-y-2">
              <label className="block text-sm font-semibold text-gray-700">Pilih Murid</label>
              <select
                required
                name="student_id"
                value={formData.student_id}
                onChange={handleChange}
                className="w-full h-14 px-4 border border-gray-200 rounded-xl focus:ring-2 focus:ring-[#2D5A27] focus:border-transparent outline-none appearance-none bg-gray-50"
              >
                <option value="">-- Pilih Nama Murid --</option>
                {students.map((student) => (
                  <option key={student.id} value={student.id}>
                    {student.name} (Kelas {student.grade})
                  </option>
                ))}
              </select>
            </div>

            {/* SFL Assessment */}
            <div className="space-y-6">
              <h3 className="text-lg font-bold text-gray-800 border-b pb-2">Asesmen SFL (1-5)</h3>

              <div className="space-y-4">
                {[
                  { id: 'sfl_existential', label: 'Existential (Menamai)', value: formData.sfl_existential },
                  { id: 'sfl_relational', label: 'Relational (Menjelaskan Diri)', value: formData.sfl_relational },
                  { id: 'sfl_material', label: 'Material (Melakukan)', value: formData.sfl_material },
                ].map((sfl) => (
                  <div key={sfl.id} className="space-y-2">
                    <div className="flex justify-between items-center">
                      <label className="text-sm font-medium text-gray-700">{sfl.label}</label>
                      <span className="text-[#2D5A27] font-bold text-lg">{sfl.value}</span>
                    </div>
                    <input
                      type="range"
                      min="1"
                      max="5"
                      name={sfl.id}
                      value={sfl.value}
                      onChange={handleSliderChange}
                      className="w-full h-2 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-[#2D5A27]"
                    />
                    <div className="flex justify-between text-[10px] text-gray-400 px-1">
                      <span>Perlu Pendampingan</span>
                      <span>Sangat Mandiri</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Phonics Checklist */}
            <div className="space-y-4">
              <h3 className="text-lg font-bold text-gray-800 border-b pb-2">Phonics Checklist</h3>
              <div className="grid grid-cols-3 gap-3">
                {PHONICS_SOUNDS.map((sound) => (
                  <button
                    key={sound}
                    type="button"
                    onClick={() => handlePhonicsChange(sound)}
                    className={`h-14 rounded-xl font-bold text-lg transition-all ${
                      formData.phonics_practiced.includes(sound)
                        ? 'bg-[#2D5A27] text-white shadow-md'
                        : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                    }`}
                  >
                    {sound}
                  </button>
                ))}
              </div>
            </div>

            {/* YouTube Spotlight */}
            <div className="space-y-2">
              <label className="block text-sm font-semibold text-gray-700">YouTube Unlisted URL</label>
              <input
                type="url"
                name="youtube_url"
                value={formData.youtube_url}
                onChange={handleChange}
                placeholder="https://youtube.com/..."
                className="w-full h-12 px-4 border border-gray-200 rounded-xl focus:ring-2 focus:ring-[#2D5A27] focus:border-transparent outline-none bg-gray-50"
              />
            </div>

            {/* Message Display */}
            {message && (
              <div className={`p-4 rounded-xl text-center font-bold ${
                message.type === 'success' ? 'bg-green-100 text-[#2D5A27]' : 'bg-red-100 text-red-600'
              }`}>
                {message.text}
              </div>
            )}

            {/* Submit Button */}
            <button
              type="submit"
              disabled={isSubmitting || !formData.student_id}
              className="w-full h-16 bg-[#2D5A27] text-white rounded-2xl font-bold text-lg hover:bg-[#23481F] transition-all disabled:opacity-50 shadow-lg"
            >
              {isSubmitting ? 'Menyimpan...' : 'Simpan Laporan Sesi'}
            </button>
          </form>
        </div>
      </main>

      <Footer />
    </div>
  );
}

'use client';

import React, { useState } from 'react';

interface RegistrationModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const RegistrationModal: React.FC<RegistrationModalProps> = ({ isOpen, onClose }) => {
  const [formData, setFormData] = useState({
    student_name: '',
    student_grade: '1',
    parent_name: '',
    whatsapp_number: '',
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };


  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);

    try {
      const response = await fetch('/api/leads', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      if (response.ok) {
        setIsSuccess(true);
      } else {
        const data = await response.json();
        setError(data.error || 'Terjadi kesalahan. Silakan coba lagi.');
      }
    } catch (err) {
      setError('Gagal mengirim data. Periksa koneksi Anda.');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (!isOpen) return null;

  const handleOverlayClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4" onClick={handleOverlayClick}>
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden relative transition-all duration-300 transform opacity-100 scale-100">
        {/* Close Button */}
        <button
          onClick={onClose}
          className="absolute top-4 right-4 text-gray-400 hover:text-gray-600 transition-colors"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>

        <div className="p-8">
          {!isSuccess ? (
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="mb-6">
                <h2 className="text-2xl font-bold text-[#2D5A27] mb-2">Formulir Pendaftaran</h2>
                <p className="text-sm text-gray-600">Lengkapi data di bawah ini untuk mendaftarkan anak Anda.</p>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Nama Lengkap Anak</label>
                <input
                  required
                  type="text"
                  name="student_name"
                  value={formData.student_name}
                  onChange={handleChange}
                  placeholder="Contoh: Andi Pratama"
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#2D5A27] focus:border-transparent outline-none"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Kelas (SD)</label>
                <select
                  name="student_grade"
                  value={formData.student_grade}
                  onChange={handleChange}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#2D5A27] focus:border-transparent outline-none"
                >
                  {[1, 2, 3, 4, 5, 6].map((g) => (
                    <option key={g} value={g}>Kelas {g}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Nama Orang Tua</label>
                <input
                  required
                  type="text"
                  name="parent_name"
                  value={formData.parent_name}
                  onChange={handleChange}
                  placeholder="Contoh: Ibu Siti"
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#2D5A27] focus:border-transparent outline-none"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Nomor WhatsApp</label>
                <input
                  required
                  type="tel"
                  name="whatsapp_number"
                  value={formData.whatsapp_number}
                  onChange={handleChange}
                  placeholder="0812XXXXXXXX"
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#2D5A27] focus:border-transparent outline-none"
                />
              </div>

              {error && <p className="text-red-500 text-sm mt-2">{error}</p>}

              <button
                type="submit"
                disabled={isSubmitting || !formData.student_name || !formData.parent_name || !formData.whatsapp_number}
                className="w-full bg-[#2D5A27] text-white py-3 rounded-xl font-bold hover:bg-[#23481F] transition-colors disabled:opacity-50 mt-6"
              >
                {isSubmitting ? 'Mengirim...' : 'Daftar Sekarang'}
              </button>
            </form>
          ) : (
            <div className="text-center py-6 animate-in zoom-in-95 duration-300">
              <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <svg className="w-8 h-8 text-[#2D5A27]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" />
                </svg>
              </div>
              <h2 className="text-3xl font-bold text-[#2D5A27] mb-2">Terima Kasih!</h2>
              <p className="text-gray-600 mb-8">
                Data Anda sudah kami terima. Kami akan segera menghubungi Bapak/Ibu <strong>{formData.parent_name}</strong> melalui WhatsApp.
              </p>
              <button
                onClick={onClose}
                className="w-full bg-[#2D5A27] text-white py-3 rounded-xl font-bold hover:bg-[#23481F] transition-colors"
              >
                Tutup
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default RegistrationModal;

'use client';

import React, { useEffect, useRef } from 'react';
import Image from 'next/image';
import Link from 'next/link';

interface SectionProps {
  id: string;
  title: React.ReactNode;
  description: React.ReactNode;
  image: string;
  reverse?: boolean;
  buttonText?: string;
  buttonLink?: string;
  accentButton?: boolean;
  onCTA?: () => void;
}

export default function Section({
  id,
  title,
  description,
  image,
  reverse = false,
  buttonText,
  buttonLink = '#contact',
  accentButton = false,
  onCTA,
}: SectionProps) {
  const sectionRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const imageRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleScroll = () => {
      if (!sectionRef.current) return;

      const rect = sectionRef.current.getBoundingClientRect();
      const windowHeight = window.innerHeight;

      if (rect.top < windowHeight && rect.bottom > 0) {
        const progress = (windowHeight - rect.top) / (windowHeight + rect.height);

        // Parallax effect for the section
        const yOffset = (rect.top - windowHeight / 2) * 0.1;
        if (contentRef.current) {
          contentRef.current.style.transform = `translateY(${yOffset}px)`;
        }
      }
    };

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            const elements = entry.target.querySelectorAll('.fade-in, .slide-in-left, .slide-in-right');
            elements.forEach((el, index) => {
              setTimeout(() => {
                el.classList.add('visible');
              }, index * 100);
            });
          }
        });
      },
      { threshold: 0.2 }
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }

    window.addEventListener('scroll', handleScroll);
    handleScroll();

    return () => {
      observer.disconnect();
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);

  return (
    <section id={id} ref={sectionRef} className="section">
      <div className="absolute inset-0 bg-gradient-to-br from-[#faf8f5] to-white" />

      <div className="section-content relative z-10">
        <div className={`section-grid ${reverse ? 'section-grid--reverse' : ''}`}>
          <div ref={imageRef} className="section-image slide-in-left">
            <Image 
              src={image} 
              alt={typeof title === 'string' ? title : id}
              width={720}
              height={720}
              style={{ objectFit: 'cover' }}
            />
          </div>
          <div ref={contentRef} className="section-text slide-in-right">
            <h2 className="section-title">{title}</h2>
            <div className="section-description">{description}</div>
            {buttonText && (
              <div className="btn-container">
                {onCTA ? (
                  <button 
                    onClick={onCTA}
                    className={`btn ${accentButton ? 'btn--accent' : ''}`}
                  >
                    {buttonText}
                  </button>
                ) : (
                  <Link href={buttonLink} className={`btn ${accentButton ? 'btn--accent' : ''}`}>
                    {buttonText}
                  </Link>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </section>
  );
}

import { Pool } from 'pg';

const pool = new Pool({
  host: process.env.DB_HOST || 'localhost',
  port: parseInt(process.env.DB_PORT || '5432'),
  user: process.env.DB_USER || 'postgres',
  password: process.env.DB_PASSWORD,
  database: process.env.DB_DATABASE || 'tiasa_db',
});

// Helper for parameterized queries
export const query = (text: string, params?: any[]) => pool.query(text, params);

export default pool;
